class Slidezy{constructor(selector,options={}){this.container=document.querySelector(selector);if(!this.container){console.error(`Element with selector "${selector}" not found.`);return}this.options=Object.assign({slideDuration:3e3,transitionDuration:500,autoplay:true,loop:true,items:1,step:null,nav:true,control:true,controlText:["<",">"],prevButton:null,nextButton:null},options);this.options.step??=this.options.items;if(this.options.step<=0){console.warn("Step must be greater than 0. Defaulting to 1.");this.options.step=1}this.index=0;this.timer=null;this.isAnimating=false;this.destroyed=false;this.handlerDots=[];this.originalChildren=Array.from(this.container.children);this._createBuild();this._cacheElements();this._init()}_createBuild(){this.container.classList.add("slidezy");const content=document.createElement("div");content.classList.add("slidezy-content");const track=document.createElement("div");track.classList.add("slidezy-track");const slides=this.originalChildren;if(slides.length===0){console.error("No slides found in the container.");return}slides.forEach(slide=>{slide.classList.add("slidezy-slide");track.appendChild(slide)});this.container.replaceChildren(content);content.appendChild(track);if(this.options.control){const prevBtn=document.createElement("button");prevBtn.classList.add("slidezy-prev");prevBtn.innerHTML=this.options.controlText?.[0]??"&#10094;";const nextBtn=document.createElement("button");nextBtn.classList.add("slidezy-next");nextBtn.innerHTML=this.options.controlText?.[1]??"&#10095;";content.appendChild(prevBtn);content.appendChild(nextBtn)}if(this.options.nav){const dotsContainer=document.createElement("div");dotsContainer.classList.add("slidezy-nav");const totalDots=this._calculateDots(slides.length);for(let i=0;i<totalDots;i++){const dot=document.createElement("span");dot.classList.add("slidezy-dot");if(i===0)dot.classList.add("active");dotsContainer.appendChild(dot)}this.container.appendChild(dotsContainer)}}_calculateDots(slideCount){if(this.options.loop){return Math.ceil(slideCount/this.options.step)}if(slideCount<=this.options.items)return 1;return Math.ceil((slideCount-this.options.items)/this.options.step)+1}_cacheElements(){this.track=this.container.querySelector(".slidezy-track");this.slides=this.track.querySelectorAll(".slidezy-slide");this.realSlidesCount=this.slides.length;this.options.items=Math.min(this.options.items,this.realSlidesCount);this.options.step=Math.min(this.options.step,this.realSlidesCount);this.prevBtn=this.options.prevButton&&document.querySelector(this.options.prevButton)||this.container.querySelector(".slidezy-prev");this.nextBtn=this.options.nextButton&&document.querySelector(this.options.nextButton)||this.container.querySelector(".slidezy-next");this.dots=this.container.querySelectorAll(".slidezy-dot")}_init(){if(this.options.loop){this._setupCloneSlides()}this._setSlidesStyle();this.track.style.transition=`transform ${this.options.transitionDuration}ms ease`;this.bindEvents();this.update();if(this.options.autoplay){this.startAutoplay()}let resizeTimeout;this.resizeHandler=()=>{clearTimeout(resizeTimeout);resizeTimeout=setTimeout(()=>{this._setSlidesStyle();this.index=this._clampIndex(this.index);this.update()},100)};window.addEventListener("resize",this.resizeHandler)}_getCloneCount(){return Math.min(Math.max(this.options.items,this.options.step),this.realSlidesCount)}_clampIndex(index){if(this.options.loop)return index;const maxIndex=Math.max(0,this.realSlidesCount-this.options.items);return Math.max(0,Math.min(index,maxIndex))}bindEvents(){this.handlerPrev=()=>this.prevSlide();this.handlerNext=()=>this.nextSlide();this.prevBtn?.addEventListener("click",this.handlerPrev);this.nextBtn?.addEventListener("click",this.handlerNext);this.dots.forEach((dot,index)=>{const handler=()=>{if(this.isAnimating)return;const targetIndex=index*this.options.step;if(this.options.loop){const cloneCount=this._getCloneCount();this.goToSlide(targetIndex+cloneCount)}else{this.goToSlide(targetIndex)}};this.handlerDots.push(handler);dot.addEventListener("click",handler)});this.transitionEndHandler=e=>{if(e.propertyName!=="transform")return;this.isAnimating=false;if(!this.options.loop)return;const cloneCount=this._getCloneCount();const totalSlides=this.slides.length;if(this.index>=totalSlides-cloneCount){this.track.style.transition="none";this.index=cloneCount;this.update();requestAnimationFrame(()=>{requestAnimationFrame(()=>{this.track.style.transition=`transform ${this.options.transitionDuration}ms ease`})});return}if(this.index<cloneCount){this.track.style.transition="none";this.index=totalSlides-cloneCount*2;this.update();requestAnimationFrame(()=>{requestAnimationFrame(()=>{this.track.style.transition=`transform ${this.options.transitionDuration}ms ease`})});return}};this.track.addEventListener("transitionend",this.transitionEndHandler)}_setSlidesStyle(){const percent=100/this.options.items;this.track.style.display="flex";if(!this.slides.length)return;this.slides.forEach(slide=>{slide.style.flex=`0 0 ${percent}%`})}update(){const slideWidth=100/this.options.items;this.track.style.transform=`translateX(-${this.index*slideWidth}%)`;this.updateDots();if(this.options.transitionDuration===0){this.isAnimating=false}}updateDots(){if(!this.dots.length)return;this.dots.forEach(dot=>dot.classList.remove("active"));let realIndex=this.index;if(this.options.loop){const cloneCount=this._getCloneCount();realIndex=(this.index-cloneCount+this.realSlidesCount)%this.realSlidesCount}const pageIndex=Math.max(0,Math.min(Math.floor(realIndex/this.options.step),this.dots.length-1));if(pageIndex>=0&&pageIndex<this.dots.length){this.dots[pageIndex].classList.add("active")}}_setupCloneSlides(){const cloneCount=this._getCloneCount();const slideArray=Array.from(this.slides);const fragmentStart=document.createDocumentFragment();const fragmentEnd=document.createDocumentFragment();const start=Math.max(0,this.slides.length-cloneCount);for(let i=start;i<slideArray.length;i++){const clone=slideArray[i].cloneNode(true);fragmentStart.appendChild(clone)}for(let i=0;i<cloneCount;i++){const clone=slideArray[i].cloneNode(true);fragmentEnd.appendChild(clone)}this.track.insertBefore(fragmentStart,this.slides[0]);this.track.appendChild(fragmentEnd);this.slides=this.track.querySelectorAll(".slidezy-slide");this.index=cloneCount}_handlerUserInteraction(){if(this.options.autoplay){this.stopAutoplay();this.startAutoplay()}}nextSlide(){if(this.isAnimating)return;this._handlerUserInteraction();if(this.options.loop){this.isAnimating=true;this.index+=this.options.step;this.update();return}const maxIndex=Math.max(0,this.realSlidesCount-this.options.items);if(this.index>=maxIndex)return;this.isAnimating=true;this.index=Math.min(this.index+this.options.step,maxIndex);this.update()}prevSlide(){if(this.isAnimating)return;this._handlerUserInteraction();if(this.options.loop){this.isAnimating=true;this.index-=this.options.step;this.update();return}if(this.index<=0)return;this.isAnimating=true;this.index=Math.max(this.index-this.options.step,0);this.update()}goToSlide(index){if(this.isAnimating)return;this.isAnimating=true;this.index=this._clampIndex(index);this.update();if(this.options.transitionDuration===0){this.isAnimating=false}}startAutoplay(){this.stopAutoplay();if(this.options.autoplay){this.timer=setInterval(()=>{if(!this.isAnimating)this.nextSlide()},this.options.slideDuration)}}stopAutoplay(){clearInterval(this.timer);this.timer=null}destroy(){if(this.destroyed)return;this.destroyed=true;this.prevBtn?.removeEventListener("click",this.handlerPrev);this.nextBtn?.removeEventListener("click",this.handlerNext);this.dots.forEach((dot,index)=>{dot.removeEventListener("click",this.handlerDots[index])});this.track?.removeEventListener("transitionend",this.transitionEndHandler);window.removeEventListener("resize",this.resizeHandler);this.stopAutoplay();this.originalChildren.forEach(slide=>{slide.classList.remove("slidezy-slide");slide.style.flex=""});this.container.replaceChildren(...this.originalChildren);this.container.classList.remove("slidezy")}}const slidezy=new Slidezy("#mySlider",{slideDuration:4e3,transitionDuration:600,autoplay:false,loop:true,items:1,step:1,nav:true,control:true,controlText:["<",">"],prevButton:".slide-prev",nextButton:".slide-next"});